```class Solution {
public:
    vector<int> powerfulIntegers(int x, int y, int bound) {
        vector<int> result;
        for (int i = 0; i <= bound / x; i++) {
            for (int j = 0; j <= bound / y; j++) {
                int sum = i * x + j * y;
                if (sum <= bound && !result.contains(sum)) {
                    result.push_back(sum);
                }
            }
        }
        return result;
    }
};
```

